import os
import json
from dotenv import load_dotenv
from openai.embeddings_utils import get_model, EmbeddingModel

# Load environment variables from .env file
load_dotenv()

# Set OpenAI API key and GPT model name
OPENAI_API_KEY = os.getenv('OPENAI_API_KEY')
GPT_MODEL_NAME = 'text-davinci-003'

def process_request(input_text):
    # Create an instance of the EmbeddingModel class
    model = get_model(GPT_MODEL_NAME)

    # Convert user input to a list of text embeddings
    response = model.embed_text(input_text).data

    return response

def main():
    print("Welcome to our customer support assistant!")
    
    while True:
        # Get user message
        user_message = input("User: ")
        
        # Concatenate system instructions with user input
        if 'hello' in user_message.lower() or 'hi' in user_message.lower():
            instruction = "Hello! How can I assist you today?"
            full_input = instruction + ' ' + user_message
        elif 'goodbye' in user_message.lower() or 'bye' in user_message.lower():
            instruction = "Goodbye! Have a nice day!"
            full_input = instruction + ' ' + user_message
        else:
            full_input = user_message
        
        # Process the request and get the response from OpenAI API
        try:
            response = process_request(full_input)
            
            # Print the model response directly to the user
            print("Assistant: ", response[0]['embedding'])
        
        except Exception as e:
            print(f"Error processing request: {e}")

if __name__ == "__main__":
    main()